  "sourcesContent": [":host{\n\tdisplay:block;\n\tmin-height:100dvh;\n\tbackground:\n\t\tradial-gradient(circle at 18% 12%, rgba(255, 177, 89, 0.14), transparent 34%),\n\t\tradial-gradient(circle at 82% 88%, rgba(255, 120, 57, 0.1), transparent 28%),\n\t\tlinear-gradient(160deg, #120f0a 0%, #1d120f 44%, #2c1911 100%);\n\tcolor:#f7f3eb;\n}\n\n.profile-shell {\n\tdisplay: grid;\n\tgap: 1rem;\n\tmax-width: 1180px;\n\tmargin: 0 auto;\n\tpadding: 1rem;\n}\n\n.status {\n\tmargin: 0;\n\tpadding: 0.75rem 0.85rem;\n\tborder-radius: 0.8rem;\n\tborder: 1px solid rgba(255, 225, 178, 0.2);\n\tbackground: rgba(14, 10, 7, 0.58);\n\tcolor: #f0e2cd;\n}\n\n.status.error {\n\tborder-color: rgba(130, 58, 74, 0.85);\n\tbackground: rgba(54, 22, 30, 0.84);\n\tcolor: #ffd2dc;\n}\n\n.status.success {\n\tborder-color: rgba(255, 204, 122, 0.4);\n\tbackground: rgba(56, 37, 18, 0.72);\n\tcolor: #ffe1b5;\n}\n\n.editor-panel {\n\tdisplay: grid;\n\tgap: 0.85rem;\n\tpadding: 1rem;\n\tborder-radius: 1rem;\n\tborder: 1px solid rgba(255, 225, 178, 0.2);\n\tbackground: rgba(33, 25, 18, 0.78);\n\tbackdrop-filter: blur(8px);\n}\n\n.editor-form {\n\tdisplay: grid;\n\tgap: 0.85rem;\n}\n\n.editor-form label {\n\tdisplay: grid;\n\tgap: 0.4rem;\n\tcolor: #cfbca2;\n\tfont-size: 0.95rem;\n}\n\n.editor-form input {\n\twidth: 100%;\n\tpadding: 0.9rem 1rem;\n\tborder-radius: 0.85rem;\n\tborder: 1px solid rgba(255, 225, 178, 0.2);\n\tbackground: rgba(12, 9, 7, 0.72);\n\tcolor: #f7f3eb;\n}\n\n.editor-form input:focus {\n\toutline: 2px solid #ffb14c;\n\toutline-offset: 2px;\n}\n\n.editor-actions {\n\tdisplay: flex;\n\tflex-wrap: wrap;\n\tgap: 0.75rem;\n\talign-items: center;\n}\n\n.panel-head {\n\tflex-wrap: wrap;\n}\n\n.panel-action {\n\tmargin-left: auto;\n\tpadding-inline: 0.95rem;\n\tfont-size: 0.95rem;\n}\n\n.book-finder {\n\tdisplay: grid;\n\tgap: 0.9rem;\n\tpadding: 0.95rem;\n\tborder: 1px solid rgba(255, 225, 178, 0.16);\n\tborder-radius: 0.95rem;\n\tbackground: rgba(14, 10, 7, 0.42);\n\tmargin-bottom: 1rem;\n}\n\n.finder-toolbar {\n\tdisplay: grid;\n\tgrid-template-columns: minmax(0, 1fr) auto auto;\n\tgap: 0.65rem;\n\talign-items: center;\n}\n\n.finder-toolbar input {\n\twidth: 100%;\n\tpadding: 0.88rem 0.95rem;\n\tborder-radius: 0.85rem;\n\tborder: 1px solid rgba(255, 225, 178, 0.18);\n\tbackground: rgba(12, 9, 7, 0.72);\n\tcolor: #f7f3eb;\n}\n\n.finder-toolbar input:focus {\n\toutline: 2px solid #ffb14c;\n\toutline-offset: 2px;\n}\n\n.finder-results {\n\tdisplay: grid;\n\tgap: 0.75rem;\n\tmax-height: 360px;\n\toverflow: auto;\n}\n\n.finder-result {\n\tdisplay: grid;\n\tgrid-template-columns: 72px minmax(0, 1fr) auto;\n\tgap: 0.8rem;\n\talign-items: center;\n\tpadding: 0.75rem;\n\tborder-radius: 0.9rem;\n\tborder: 1px solid rgba(255, 225, 178, 0.12);\n\tbackground: rgba(33, 25, 18, 0.66);\n}\n\n.finder-cover {\n\twidth: 72px;\n\theight: 100px;\n\tborder-radius: 0.7rem;\n\tbackground: linear-gradient(160deg, rgba(255, 177, 89, 0.25), rgba(255, 120, 57, 0.18));\n\tborder: 1px solid rgba(255, 225, 178, 0.22);\n}\n\n.finder-copy {\n\tdisplay: grid;\n\tgap: 0.25rem;\n}\n\n.finder-copy strong {\n\tfont-size: 1rem;\n}\n\n.finder-copy p,\n.finder-copy span {\n\tmargin: 0;\n\tcolor: #cfbca2;\n\tfont-size: 0.92rem;\n}\n\n.finder-action {\n\twhite-space: nowrap;\n}\n\n.finder-empty {\n\tmargin: 0;\n\tcolor: #cfbca2;\n}\n\n.inline-action {\n\tmargin-left: 0.55rem;\n\tpadding: 0.42rem 0.8rem;\n\tfont-size: 0.92rem;\n}\n\n.preview-actions {\n\tjustify-content: flex-start;\n}\n\n.primary-action:disabled {\n\topacity: 0.7;\n\tcursor: progress;\n}\n\n.profile-shell .profile-hero {\n\tpadding-top: 0.35rem;\n}\n\n.edit-shell {\n\tmin-height: calc(100dvh - 3rem);\n\tdisplay: grid;\n\tplace-items: center;\n\tpadding: 0.4rem 0;\n}\n\n.edit-card {\n\twidth: min(580px, 100%);\n\tborder-radius: 1.1rem;\n\tborder: 1px solid rgba(255, 225, 178, 0.2);\n\tbackground: linear-gradient(170deg, rgba(33, 25, 18, 0.92), rgba(18, 12, 9, 0.94));\n\tpadding: 1.2rem;\n\tbox-shadow: 0 18px 50px rgba(0, 0, 0, 0.35);\n\tdisplay: grid;\n\tgap: 1rem;\n}\n\n.edit-head {\n\tdisplay: grid;\n\tgap: 0.35rem;\n\tpadding-bottom: 0.8rem;\n\tborder-bottom: 1px solid rgba(255, 225, 178, 0.16);\n}\n\n.edit-eyebrow {\n\tmargin: 0;\n\tfont-size: 0.78rem;\n\tletter-spacing: 0.1em;\n\ttext-transform: uppercase;\n\tcolor: #ffd18b;\n\tfont-weight: 700;\n}\n\n.edit-head h1 {\n\tmargin: 0;\n\tfont-size: clamp(1.6rem, 3vw, 2rem);\n\tletter-spacing: -0.02em;\n}\n\n.edit-head p {\n\tmargin: 0;\n\tcolor: #cfbca2;\n}\n\n.btn-edit,\n.btn-save,\n.btn-cancel {\n\tborder-radius: 999px;\n\tpadding: 0.6rem 1rem;\n\tfont-weight: 700;\n\tfont: inherit;\n\tcursor: pointer;\n\ttransition: transform 140ms ease, box-shadow 140ms ease, background 140ms ease, color 140ms ease;\n}\n\n.btn-edit,\n.btn-save {\n\tbackground: linear-gradient(90deg, rgba(255, 204, 122, 0.16), rgba(255, 157, 82, 0.14));\n\tcolor: #ffd18b;\n\tborder: 1px solid rgba(255, 204, 122, 0.35);\n\tbox-shadow: inset 0 0 0 1px rgba(255, 177, 89, 0.18);\n}\n\n.btn-edit:hover,\n.btn-save:hover {\n\tbackground: linear-gradient(95deg, #f8b84e, #ff8f3c);\n\tcolor: #1c130f;\n\ttransform: translateY(-1px);\n}\n\n.btn-cancel {\n\tbackground: rgba(33, 25, 18, 0.78);\n\tcolor: #f4dcc2;\n\tborder: 1px solid rgba(255, 225, 178, 0.24);\n}\n\n.btn-cancel:hover {\n\tbackground: rgba(44, 25, 17, 0.88);\n\ttransform: translateY(-1px);\n}\n\n/* Override global profile blocks from styles.css to keep one visual language */\n:host .profile-hero,\n:host .profile-tabs,\n:host .panel,\n:host .promo-card,\n:host .book-card,\n:host .activity-card {\n\tborder-color: rgba(255, 225, 178, 0.18);\n}\n\n:host .profile-hero {\n\tborder-bottom-color: rgba(255, 225, 178, 0.2);\n}\n\n:host .avatar-block {\n\tbackground: linear-gradient(180deg, rgba(255, 177, 89, 0.25), rgba(255, 120, 57, 0.2));\n\tborder-color: rgba(255, 225, 178, 0.3);\n}\n\n:host .avatar-face {\n\tbackground: rgba(255, 209, 139, 0.3);\n\tbox-shadow: 0 1.85rem 0 0.9rem rgba(255, 209, 139, 0.3);\n}\n\n:host .hero-subtitle,\n:host .panel-head span,\n:host .empty-state,\n:host .book-info p,\n:host .activity-card p,\n:host .metric-card span {\n\tcolor: #cfbca2;\n}\n\n:host .profile-tabs {\n\tborder-bottom-color: rgba(255, 225, 178, 0.16);\n}\n\n:host .tab-button {\n\tcolor: #cfbca2;\n}\n\n:host .tab-button.active {\n\tbackground: linear-gradient(90deg, rgba(255, 204, 122, 0.16), rgba(255, 157, 82, 0.14));\n\tcolor: #ffd18b;\n\tborder-color: rgba(255, 204, 122, 0.3);\n}\n\n:host .panel,\n:host .promo-card {\n\tbackground: linear-gradient(180deg, rgba(33, 25, 18, 0.78), rgba(18, 12, 9, 0.9));\n}\n\n:host .book-card,\n:host .activity-card {\n\tbackground: rgba(14, 10, 7, 0.58);\n}\n\n:host .book-cover {\n\tbackground: linear-gradient(145deg, rgba(255, 177, 89, 0.25), rgba(255, 120, 57, 0.18));\n\tborder-color: rgba(255, 225, 178, 0.24);\n}\n\n:host .promo-eyebrow {\n\tcolor: #ffd18b;\n}\n\n:host .promo-button {\n\tbackground: linear-gradient(95deg, #f8b84e, #ff8f3c);\n\tcolor: #1c130f;\n\tbox-shadow: 0 10px 24px rgba(255, 143, 60, 0.25);\n}\n\n.btn-save:disabled {\n\topacity: 0.7;\n\tcursor: progress;\n\ttransform: none;\n}\n\n@media (max-width: 720px) {\n\t.profile-shell {\n\t\tpadding: 0.85rem;\n\t}\n\n\t.editor-panel {\n\t\tpadding: 0.9rem;\n\t}\n\n\t.editor-actions {\n\t\tflex-direction: column;\n\t\talign-items: stretch;\n\t}\n\n\t.editor-actions .primary-action,\n\t.editor-actions .ghost-action {\n\t\twidth: 100%;\n\t}\n\n\t.edit-card {\n\t\tpadding: 1rem;\n\t\tborder-radius: 1rem;\n\t}\n\n\t.editor-actions .btn-save,\n\t.editor-actions .btn-cancel {\n\t\twidth: 100%;\n\t}\n\n\t.panel-head {\n\t\talign-items: flex-start;\n\t}\n\n\t.panel-action {\n\t\twidth: 100%;\n\t\tmargin-left: 0;\n\t}\n\n\t.finder-toolbar {\n\t\tgrid-template-columns: 1fr;\n\t}\n\n\t.finder-result {\n\t\tgrid-template-columns: 1fr;\n\t}\n\n\t.finder-action {\n\t\twidth: 100%;\n\t}\n}"],
