  "sourcesContent": [":host{\r\n\tdisplay:block;\r\n\tmin-height:100dvh;\r\n\tbackground:\r\n\t\tradial-gradient(circle at top, rgba(32, 48, 68, 0.5), transparent 32%),\r\n\t\tlinear-gradient(180deg, #0b1219 0%, #0e151e 100%);\r\n\tcolor:#edf3f9;\r\n}\r\n\r\n.profile-shell {\r\n\tdisplay: grid;\r\n\tgap: 1rem;\r\n\tmax-width: 1180px;\r\n\tmargin: 0 auto;\r\n\tpadding: 1rem;\r\n}\r\n\r\n.status {\r\n\tmargin: 0;\r\n\tpadding: 0.75rem 0.85rem;\r\n\tborder-radius: 0.8rem;\r\n\tborder: 1px solid rgba(111, 130, 150, 0.35);\r\n\tbackground: rgba(17, 24, 33, 0.82);\r\n\tcolor: #d9e6f3;\r\n}\r\n\r\n.status.error {\r\n\tborder-color: rgba(130, 58, 74, 0.85);\r\n\tbackground: rgba(54, 22, 30, 0.84);\r\n\tcolor: #ffd2dc;\r\n}\r\n\r\n.status.success {\r\n\tborder-color: rgba(29, 215, 96, 0.35);\r\n\tbackground: rgba(20, 43, 28, 0.84);\r\n\tcolor: #bff3cf;\r\n}\r\n\r\n.editor-panel {\r\n\tdisplay: grid;\r\n\tgap: 0.85rem;\r\n\tpadding: 1rem;\r\n\tborder-radius: 1rem;\r\n\tborder: 1px solid rgba(78, 94, 110, 0.45);\r\n\tbackground: rgba(12, 18, 26, 0.72);\r\n\tbackdrop-filter: blur(8px);\r\n}\r\n\r\n.editor-form {\r\n\tdisplay: grid;\r\n\tgap: 0.85rem;\r\n}\r\n\r\n.editor-form label {\r\n\tdisplay: grid;\r\n\tgap: 0.4rem;\r\n\tcolor: #b7c7d6;\r\n\tfont-size: 0.95rem;\r\n}\r\n\r\n.editor-form input {\r\n\twidth: 100%;\r\n\tpadding: 0.9rem 1rem;\r\n\tborder-radius: 0.85rem;\r\n\tborder: 1px solid #344556;\r\n\tbackground: #0f1720;\r\n\tcolor: #edf3f9;\r\n}\r\n\r\n.editor-form input:focus {\r\n\toutline: 2px solid #1fd760;\r\n\toutline-offset: 2px;\r\n}\r\n\r\n.editor-actions {\r\n\tdisplay: flex;\r\n\tflex-wrap: wrap;\r\n\tgap: 0.75rem;\r\n\talign-items: center;\r\n}\r\n\r\n.preview-actions {\r\n\tjustify-content: flex-start;\r\n}\r\n\r\n.primary-action:disabled {\r\n\topacity: 0.7;\r\n\tcursor: progress;\r\n}\r\n\r\n.profile-shell .profile-hero {\r\n\tpadding-top: 0.35rem;\r\n}\r\n\r\n.edit-shell {\r\n\tmin-height: calc(100dvh - 3rem);\r\n\tdisplay: grid;\r\n\tplace-items: center;\r\n\tpadding: 0.4rem 0;\r\n}\r\n\r\n.edit-card {\r\n\twidth: min(580px, 100%);\r\n\tborder-radius: 1.1rem;\r\n\tborder: 1px solid rgba(74, 90, 104, 0.62);\r\n\tbackground: linear-gradient(170deg, rgba(12, 18, 26, 0.95), rgba(16, 25, 35, 0.95));\r\n\tpadding: 1.2rem;\r\n\tbox-shadow: 0 18px 50px rgba(0, 0, 0, 0.35);\r\n\tdisplay: grid;\r\n\tgap: 1rem;\r\n}\r\n\r\n.edit-head {\r\n\tdisplay: grid;\r\n\tgap: 0.35rem;\r\n\tpadding-bottom: 0.8rem;\r\n\tborder-bottom: 1px solid rgba(74, 90, 104, 0.45);\r\n}\r\n\r\n.edit-eyebrow {\r\n\tmargin: 0;\r\n\tfont-size: 0.78rem;\r\n\tletter-spacing: 0.1em;\r\n\ttext-transform: uppercase;\r\n\tcolor: #a7bccf;\r\n\tfont-weight: 700;\r\n}\r\n\r\n.edit-head h1 {\r\n\tmargin: 0;\r\n\tfont-size: clamp(1.6rem, 3vw, 2rem);\r\n\tletter-spacing: -0.02em;\r\n}\r\n\r\n.edit-head p {\r\n\tmargin: 0;\r\n\tcolor: #9fb3c4;\r\n}\r\n\r\n.btn-edit,\r\n.btn-save,\r\n.btn-cancel {\r\n\tborder-radius: 999px;\r\n\tpadding: 0.6rem 1rem;\r\n\tfont-weight: 700;\r\n\tfont: inherit;\r\n\tcursor: pointer;\r\n\ttransition: transform 140ms ease, box-shadow 140ms ease, background 140ms ease, color 140ms ease;\r\n}\r\n\r\n.btn-edit,\r\n.btn-save {\r\n\tbackground: #0d141b;\r\n\tcolor: #43de7f;\r\n\tborder: 1px solid #26bf62;\r\n\tbox-shadow: inset 0 0 0 1px rgba(38, 191, 98, 0.2);\r\n}\r\n\r\n.btn-edit:hover,\r\n.btn-save:hover {\r\n\tbackground: #173320;\r\n\tcolor: #d8ffea;\r\n\ttransform: translateY(-1px);\r\n}\r\n\r\n.btn-cancel {\r\n\tbackground: #2a1a0f;\r\n\tcolor: #ffd4b0;\r\n\tborder: 1px solid #ff9b57;\r\n}\r\n\r\n.btn-cancel:hover {\r\n\tbackground: #472612;\r\n\ttransform: translateY(-1px);\r\n}\r\n\r\n.btn-save:disabled {\r\n\topacity: 0.7;\r\n\tcursor: progress;\r\n\ttransform: none;\r\n}\r\n\r\n@media (max-width: 720px) {\r\n\t.profile-shell {\r\n\t\tpadding: 0.85rem;\r\n\t}\r\n\r\n\t.editor-panel {\r\n\t\tpadding: 0.9rem;\r\n\t}\r\n\r\n\t.editor-actions {\r\n\t\tflex-direction: column;\r\n\t\talign-items: stretch;\r\n\t}\r\n\r\n\t.editor-actions .primary-action,\r\n\t.editor-actions .ghost-action {\r\n\t\twidth: 100%;\r\n\t}\r\n\r\n\t.edit-card {\r\n\t\tpadding: 1rem;\r\n\t\tborder-radius: 1rem;\r\n\t}\r\n\r\n\t.editor-actions .btn-save,\r\n\t.editor-actions .btn-cancel {\r\n\t\twidth: 100%;\r\n\t}\r\n}"],
